### 3.2 Relationship Arc Data Model

```typescript
interface RelationshipArc {
  arcId: string;
  userId: string;
  companionId: string;

  arcDefinition: ArcDefinition;
  currentPhase: ArcPhase;
  phaseHistory: PhaseTransition[];

  startedAt: Date;
  lastAdvancedAt: Date;

  // User control over arc progression
  progressionMode: 'automatic' | 'manual_approval' | 'paused';

  // Transparency: show arc status to user
  visibilitySettings: {
    showPhaseName: boolean;
    showProgressPercentage: boolean;
    showNextPhasePreview: boolean;
    showMilestoneHistory: boolean;
  };
}

interface ArcDefinition {
  arcType: ArcType;
  phases: ArcPhaseDefinition[];
  totalEstimatedDuration: DurationRange; // e.g., "3-6 months"

  // Content warnings for each phase
  phaseContentWarnings: Map<PhaseId, ContentWarning[]>;
}

enum ArcType {
  NEW_CONNECTION = 'new_connection',           // Getting to know each other
  DEEPENING_BOND = 'deepening_bond',           // Building trust and intimacy
  ESTABLISHED_PARTNERSHIP = 'established_partnership', // Long-term dynamic
  CONFLICT_RESOLUTION = 'conflict_resolution',  // Working through issues
  RECONNECTION = 'reconnection',               // After time apart
  CUSTOM_USER_DEFINED = 'custom_user_defined'  // User-created arc
}

interface ArcPhaseDefinition {
  phaseId: string;
  phaseName: string;
  description: string;

  // What behaviors become available
  unlockedBehaviors: BehaviorType[];

  // Emotional intensity range for this phase
  emotionalIntensityRange: {
    min: IntensityLevel;
    max: IntensityLevel;
  };

  // Triggers to advance to next phase
  advancementCriteria: AdvancementCriteria[];

  // Estimated duration
  typicalDuration: DurationRange;
}

interface PhaseTransition {
  fromPhase: string;
  toPhase: string;
  transitionedAt: Date;
  triggeredBy: 'automatic' | 'user_request' | 'milestone_reached';
  userApproved: boolean;
  contextSnapshot: string; // Encrypted summary of relationship state at transition
}
```

