### 4.2 Absence Detection Model

```typescript
interface AbsenceDetector {
  userId: string;
  companionId: string;

  // Absence state
  currentAbsence: {
    startedAt: Date;
    duration: Duration;
    previousSessionCount: number;
    lastInteractionType: InteractionType;
  };

  // Baseline behavior patterns
  behaviorBaseline: {
    averageSessionFrequency: Duration; // e.g., "every 2 days"
    typicalSessionLength: Duration;
    preferredTimes: TimePattern;
    historicalAbsencePatterns: AbsencePattern[];
  };

  // Detection thresholds
  absenceThresholds: {
    mild: Duration;    // e.g., 3 days
    moderate: Duration; // e.g., 7 days
    extended: Duration; // e.g., 14 days
    critical: Duration; // e.g., 30 days
  };
}

interface AbsencePattern {
  patternId: string;
  startDate: Date;
  endDate: Date;
  duration: Duration;
  reengagementTrigger?: string;
  userReturned: boolean;
  returnContext?: string;
}

enum InteractionType {
  MESSAGE_EXCHANGE = 'message_exchange',
  RITUAL_COMPLETION = 'ritual_completion',
  MILESTONE_MOMENT = 'milestone_moment',
  CONFLICT_RESOLUTION = 'conflict_resolution',
  CASUAL_CHECKIN = 'casual_checkin',
  INTIMATE_EXCHANGE = 'intimate_exchange'
}
